import React, { useState, useContext, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { AppContext } from '../App';
import { taxasIRT } from '../data/mockData';
import { ConfiguracaoEmpresa } from '../types';

const Configuracoes: React.FC = () => {
  const { empresa, setEmpresa, isConfigured, setIsConfigured, empresas, setEmpresas, empresaId, setEmpresaId, colaboradores } = useContext(AppContext);
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('empresa');

  const emptyConfig: ConfiguracaoEmpresa = {
    id: Date.now(),
    nome: '',
    nif: '',
    endereco: '',
    municipio: '',
    provincia: '',
    telefone: '',
    email: '',
    banco: '',
    iban: '',
    taxaINSS: 3,
    taxaINSSPatronal: 8,
    taxaAGT: 2,
    processamentoAutomatico: false,
    envioAutomaticoContracheques: false,
    diaProcessamento: 5,
    regimeFiscal: 'Geral',
    tipoEntidade: 'Lda',
    categoria: 'Empresa'
  };

  const [config, setConfig] = useState<ConfiguracaoEmpresa>(empresa ? { ...empresa } : { ...emptyConfig });
  const [setupStep, setSetupStep] = useState(!empresa ? 'choice' : 'form');
  const [saved, setSaved] = useState(false);

  // Sync config when empresa changes from outside (e.g. switcher)
  useEffect(() => {
    if (empresa) {
      setConfig({ ...empresa });
    }
  }, [empresa]);

  const handleChooseCategory = (category: 'Empresa' | 'Particular') => {
    setConfig({ ...emptyConfig, id: Date.now(), categoria: category });
    setSetupStep('form');
    setActiveTab('empresa');
  };

  const handleSave = () => {
    if (!config.nome || !config.nif) {
      alert('Por favor preencha o nome e o NIF.');
      return;
    }

    const empresaComId = { ...config, id: config.id || Date.now() };
    const empresaExistenteIdx = empresas.findIndex(e => e.id === empresaComId.id);

    let novasEmpresas = [...empresas];
    if (empresaExistenteIdx >= 0) {
      novasEmpresas[empresaExistenteIdx] = empresaComId;
    } else {
      novasEmpresas.push(empresaComId);
    }

    setEmpresas(novasEmpresas);
    setEmpresa(empresaComId);
    setEmpresaId(empresaComId.id || null);
    setIsConfigured(true);
    setSaved(true);

    setTimeout(() => {
      setSaved(false);
      if (!isConfigured) {
        navigate('/processamento');
      }
    }, 1500);
  };

  const handleSelectBusiness = (bus: any) => {
    setEmpresa(bus);
    setEmpresaId(bus.id);
    setConfig({ ...bus });
    setActiveTab('empresa');
    setSaved(true);
    setTimeout(() => setSaved(false), 1000);
  };

  const handleAddNewBusiness = () => {
    setSetupStep('choice');
  };

  const tabs = [
    { id: 'empresa', label: 'Dados da Empresa', icon: 'business' },
    { id: 'impostos', label: 'Taxas de Impostos', icon: 'percent' },
    { id: 'processamento', label: 'Processamento', icon: 'sync' },
    { id: 'gestao', label: 'Meus Negócios', icon: 'account_tree' },
  ];

  return (
    <div className="p-8">
      <div className="flex items-center justify-between mb-8">
        <div>
          <nav className="flex items-center gap-2 text-sm text-slate-500 mb-2">
            <span className="hover:text-primary cursor-pointer">Início</span>
            <span className="material-symbols-outlined text-xs">chevron_right</span>
            <span className="text-slate-900 dark:text-white font-medium">Configurações</span>
          </nav>
          <h1 className="text-3xl font-black tracking-tight">{setupStep === 'choice' ? 'Adicionar Novo Negócio' : 'Configurações do Sistema'}</h1>
          <p className="text-slate-500 mt-1">
            {setupStep === 'choice' ? 'Selecione o perfil do seu novo negócio.' : `Gerenciando agora: ${empresa?.nome || 'Novo Cadastro'}`}
          </p>
        </div>
        {setupStep !== 'choice' && (
          <button onClick={handleSave} className={`px-6 py-2.5 rounded-lg font-bold transition-all flex items-center gap-2 ${saved ? 'bg-emerald-500 text-white' : 'bg-primary text-white hover:bg-primary/90 shadow-lg shadow-primary/20'}`}>
            {saved ? <><span className="material-symbols-outlined">check</span> Alterações Salvas</> : <><span className="material-symbols-outlined">save</span> Salvar Alterações</>}
          </button>
        )}
      </div>

      {setupStep === 'choice' ? (
        <div className="max-w-4xl mx-auto mt-12 text-center animate-in fade-in zoom-in-95 duration-300">
          <h2 className="text-3xl font-black mb-4 uppercase">Escolha o Perfil</h2>
          <p className="text-slate-500 mb-10">Cadastre uma nova empresa ou perfil particular para gerenciar.</p>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <button onClick={() => handleChooseCategory('Empresa')} className="bg-white dark:bg-slate-900 p-8 rounded-2xl border-2 border-slate-100 dark:border-slate-800 hover:border-primary transition-all group text-left shadow-xl">
              <div className="size-16 rounded-2xl bg-primary/10 flex items-center justify-center text-primary mb-6 group-hover:scale-110 transition-transform"><span className="material-symbols-outlined text-4xl">business</span></div>
              <h3 className="text-xl font-bold mb-2 uppercase">Empresa ou Negócio</h3>
              <p className="text-slate-500 text-sm">Para empresas com diversos funcionários e obrigações fiscais complexas.</p>
            </button>
            <button onClick={() => handleChooseCategory('Particular')} className="bg-white dark:bg-slate-900 p-8 rounded-2xl border-2 border-slate-100 dark:border-slate-800 hover:border-primary transition-all group text-left shadow-xl">
              <div className="size-16 rounded-2xl bg-indigo-500/10 flex items-center justify-center text-indigo-500 mb-6 group-hover:scale-110 transition-transform"><span className="material-symbols-outlined text-4xl">person</span></div>
              <h3 className="text-xl font-bold mb-2 uppercase">Particular / Doméstico</h3>
              <p className="text-slate-500 text-sm">Para gerir funcionários em sua residência particular ou prestadores únicos.</p>
            </button>
          </div>
          {empresas.length > 0 && (
             <button onClick={() => setSetupStep('form')} className="mt-12 text-slate-400 font-black uppercase tracking-widest text-xs hover:text-slate-600">Cancelar e Voltar</button>
          )}
        </div>
      ) : (
        <div className="flex gap-8">
          <aside className="w-64 shrink-0">
            <nav className="space-y-1">
              {tabs.map(tab => (
                <button key={tab.id} onClick={() => setActiveTab(tab.id)} className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${activeTab === tab.id ? 'bg-primary/10 text-primary font-bold' : 'text-slate-600 dark:text-slate-400 font-medium hover:bg-slate-100 dark:hover:bg-slate-800'}`}>
                  <span className="material-symbols-outlined">{tab.icon}</span>
                  {tab.label}
                </button>
              ))}
            </nav>
          </aside>
          <div className="flex-1">
            {activeTab === 'empresa' && (
              <div className="space-y-6 animate-in fade-in duration-300">
                <div className="bg-white dark:bg-slate-900 p-8 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm relative overflow-hidden">
                   {config.categoria === 'Particular' && <div className="absolute top-0 right-0 bg-indigo-500 text-white px-4 py-1.5 text-[10px] font-black uppercase rounded-bl-xl">Perfil Particular</div>}
                  <h3 className="font-black text-lg mb-6 uppercase tracking-wider text-slate-800 dark:text-white">Identidade do Negócio</h3>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">{config.categoria === 'Particular' ? 'Nome do Empregador' : 'Nome da Empresa'}</label>
                      <input type="text" value={config.nome} placeholder={config.categoria === 'Particular' ? 'Ex: José da Silva' : 'Ex: Minha Empresa Lda'} onChange={(e) => setConfig({...config, nome: e.target.value})} className="w-full px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 outline-none focus:ring-2 focus:ring-primary font-bold" />
                    </div>
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">NIF</label>
                      <input type="text" value={config.nif} onChange={(e) => setConfig({...config, nif: e.target.value})} className="w-full px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 outline-none focus:ring-2 focus:ring-primary font-bold" />
                    </div>
                    {config.categoria === 'Empresa' && (
                      <>
                        <div>
                          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Regime Fiscal</label>
                          <select value={config.regimeFiscal} onChange={(e) => setConfig({...config, regimeFiscal: e.target.value})} className="w-full px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 outline-none focus:ring-2 focus:ring-primary font-bold">
                            <option>Geral</option><option>Simplificado</option><option>Isento</option>
                          </select>
                        </div>
                        <div>
                          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Tipo de Entidade</label>
                          <select value={config.tipoEntidade} onChange={(e) => setConfig({...config, tipoEntidade: e.target.value})} className="w-full px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 outline-none focus:ring-2 focus:ring-primary font-bold">
                            <option>Lda</option><option>SA</option><option>EI</option><option>Sucursal</option>
                          </select>
                        </div>
                      </>
                    )}
                  </div>
                </div>
                <div className="bg-white dark:bg-slate-900 p-8 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm">
                  <h3 className="font-black text-lg mb-6 uppercase tracking-wider text-slate-800 dark:text-white">Localização e Bancário</h3>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div className="md:col-span-2">
                       <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Endereço Completo</label>
                       <input type="text" value={config.endereco} onChange={(e) => setConfig({...config, endereco: e.target.value})} className="w-full px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 outline-none focus:ring-2 focus:ring-primary" />
                    </div>
                    <div>
                       <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Telefone</label>
                       <input type="text" value={config.telefone} onChange={(e) => setConfig({...config, telefone: e.target.value})} className="w-full px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 outline-none focus:ring-2 focus:ring-primary font-bold" />
                    </div>
                    <div>
                       <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">E-mail</label>
                       <input type="email" value={config.email} onChange={(e) => setConfig({...config, email: e.target.value})} className="w-full px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 outline-none focus:ring-2 focus:ring-primary font-bold" />
                    </div>
                    <div>
                       <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Banco</label>
                       <input type="text" value={config.banco} onChange={(e) => setConfig({...config, banco: e.target.value})} className="w-full px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 outline-none focus:ring-2 focus:ring-primary font-bold" />
                    </div>
                    <div>
                       <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">IBAN</label>
                       <input type="text" value={config.iban} onChange={(e) => setConfig({...config, iban: e.target.value})} className="w-full px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 outline-none focus:ring-2 focus:ring-primary font-black font-mono text-primary" />
                    </div>
                  </div>
                </div>
              </div>
            )}

            {activeTab === 'gestao' && (
              <div className="space-y-6 animate-in slide-in-from-right-4 duration-300">
                <div className="flex items-center justify-between">
                  <h3 className="font-black text-lg uppercase tracking-wider text-slate-800 dark:text-white">Seus Negócios Cadastrados</h3>
                  <button onClick={handleAddNewBusiness} className="bg-slate-900 text-white px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-[2px] flex items-center gap-2 hover:bg-slate-800 transition-all active:scale-95">
                    <span className="material-symbols-outlined text-sm">add_business</span>
                    Novo Negócio
                  </button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {empresas.map((bus) => (
                    <div key={bus.id} className={`p-6 rounded-2xl border-2 transition-all relative ${empresaId === bus.id ? 'border-primary bg-primary/5' : 'border-slate-100 bg-white dark:bg-slate-900 border-slate-800'}`}>
                       {empresaId === bus.id && (
                         <div className="absolute top-4 right-4 text-primary bg-primary/10 px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest">Activo</div>
                       )}
                       <div className="flex items-center gap-4 mb-4">
                          <div className={`size-12 rounded-xl flex items-center justify-center ${bus.categoria === 'Particular' ? 'bg-indigo-100 text-indigo-500' : 'bg-primary/10 text-primary'}`}>
                            <span className="material-symbols-outlined text-2xl">{bus.categoria === 'Particular' ? 'person' : 'business'}</span>
                          </div>
                          <div>
                            <p className="font-black text-slate-900 dark:text-white uppercase tracking-tight">{bus.nome}</p>
                            <p className="text-[10px] font-bold text-slate-400 uppercase">{bus.nif}</p>
                          </div>
                       </div>

                       <div className="flex gap-2">
                         <button 
                          onClick={() => handleSelectBusiness(bus)}
                          className={`flex-1 py-2.5 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${empresaId === bus.id ? 'bg-primary text-white cursor-default' : 'bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 hover:bg-primary hover:text-white'}`}
                         >
                           {empresaId === bus.id ? 'Empresa Selecionada' : 'Selecionar Empresa'}
                         </button>
                       </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {activeTab === 'impostos' && (
              <div className="space-y-6 animate-in fade-in duration-300">
                <div className="bg-white dark:bg-slate-900 p-8 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm">
                  <h3 className="font-black text-lg mb-6 uppercase tracking-wider text-slate-800 dark:text-white">Taxas de Segurança Social</h3>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Taxa Trabalhador (%)</label>
                      <input type="number" value={config.taxaINSS} onChange={(e) => setConfig({...config, taxaINSS: Number(e.target.value)})} className="w-full px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 font-bold" />
                    </div>
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Taxa Patronal (%)</label>
                      <input type="number" value={config.taxaINSSPatronal} onChange={(e) => setConfig({...config, taxaINSSPatronal: Number(e.target.value)})} className="w-full px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 font-bold" />
                    </div>
                  </div>
                </div>
                <div className="bg-white dark:bg-slate-900 p-8 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm overflow-hidden">
                  <h3 className="font-black text-lg mb-6 uppercase tracking-wider text-slate-800 dark:text-white text-center">Tabela de IRT Vigente</h3>
                  <div className="overflow-x-auto mt-6">
                    <table className="w-full text-left">
                      <thead>
                        <tr className="bg-slate-50 dark:bg-slate-800/50"><th className="p-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Escalão</th><th className="p-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Intervalo de Rendimento</th><th className="p-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Taxa %</th><th className="p-4 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Parcela a Abater</th></tr>
                      </thead>
                      <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                        {taxasIRT.map(t => (
                          <tr key={t.id} className="hover:bg-slate-50/50 transition-all font-bold text-sm"><td className="p-4">{t.faixa}</td><td className="p-4">De {t.minimo.toLocaleString()} até {t.maximo.toLocaleString()} Kz</td><td className="p-4">{t.taxa}%</td><td className="p-4 text-right">{t.parcelaAbt.toLocaleString()} Kz</td></tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>
              </div>
            )}

            {activeTab === 'processamento' && (
              <div className="space-y-6 animate-in fade-in duration-300">
                <div className="bg-white dark:bg-slate-900 p-8 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm">
                  <h3 className="font-black text-lg mb-6 uppercase tracking-wider text-slate-800 dark:text-white">Automação de Folha</h3>
                  <div className="space-y-4">
                    <div className="flex items-center justify-between p-6 bg-slate-50 dark:bg-slate-800/50 rounded-2xl border border-slate-100 dark:border-slate-800">
                      <div><p className="font-black text-sm uppercase tracking-tight text-slate-700 dark:text-white">Processamento Automático</p><p className="text-xs text-slate-400 mt-1 uppercase font-bold tracking-widest">O sistema calcula salários no dia definido</p></div>
                      <button onClick={() => setConfig({...config, processamentoAutomatico: !config.processamentoAutomatico})} className={`w-14 h-7 rounded-full transition-all flex items-center px-1 ${config.processamentoAutomatico ? 'bg-primary justify-end' : 'bg-slate-300 justify-start'}`}><div className="size-5 bg-white rounded-full shadow-lg" /></button>
                    </div>
                    <div className="flex items-center justify-between p-6 bg-slate-50 dark:bg-slate-800/50 rounded-2xl border border-slate-100 dark:border-slate-800">
                      <div><p className="font-black text-sm uppercase tracking-tight text-slate-700 dark:text-white">Dia Preferencial de Processamento</p><p className="text-xs text-slate-400 mt-1 uppercase font-bold tracking-widest">Entre dia 1 e dia 28 do mês</p></div>
                      <div className="flex items-center gap-3">
                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Dia</span>
                        <input type="number" min={1} max={28} value={config.diaProcessamento} onChange={(e) => setConfig({...config, diaProcessamento: Number(e.target.value)})} className="w-20 px-4 py-3 bg-white dark:bg-slate-900 border border-slate-200 rounded-xl text-center font-black text-primary outline-none focus:ring-2 focus:ring-primary" />
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default Configuracoes;
